import java.util.ArrayList;
import java.util.List;

class DinnerPlates {
    int capacity;
    List<List<Integer>> stacks;

    public DinnerPlates(int capacity) {
        this.capacity = capacity;
        stacks = new ArrayList<>();
    }

    public void push(int val) {
        for (List<Integer> stack : stacks) {
            if (stack.size() < capacity) {
                stack.add(val);
                return;
            }
        }
        stacks.add(new ArrayList<>(List.of(val)));
    }

    public int pop() {
        while (!stacks.isEmpty() && stacks.get(stacks.size() - 1).isEmpty()) {
            stacks.remove(stacks.size() - 1);
        }
        if (stacks.isEmpty()) return -1;
        List<Integer> lastStack = stacks.get(stacks.size() - 1);
        int result = lastStack.get(lastStack.size() - 1);
        lastStack.remove(lastStack.size() - 1);
        return result;
    }

    public int popAtStack(int index) {
        if (index >= stacks.size() || stacks.get(index).isEmpty()) {
            return -1;
        }
        List<Integer> stack = stacks.get(index);
        int result = stack.get(stack.size() - 1);
        stack.remove(stack.size() - 1);
        return result;
    }
}
